class Solution:
    def longestPalindrome(self, s):
        # brute: build the longest palindrome multiset directly
        from collections import Counter
        counts = Counter(s)
        length = 0
        used_center = False
        for ch, c in counts.items():
            pairs = c // 2
            length += pairs * 2
            if c % 2 == 1:
                used_center = True
        if used_center:
            length += 1
        return length

