class Solution:
    def longestPalindrome(self, s):
        from collections import Counter
        counts = Counter(s)
        result = 0
        odd_present = False
        for c in counts.values():
            result += c - (c & 1)
            if c & 1:
                odd_present = True
        return result + (1 if odd_present else 0)

