var longestPalindrome = function(s) {
    const counts = {};
    for (const ch of s) counts[ch] = (counts[ch] || 0) + 1;
    let result = 0;
    let oddPresent = false;
    for (const k in counts) {
        const c = counts[k];
        result += c - (c % 2);
        if (c % 2 === 1) oddPresent = true;
    }
    return result + (oddPresent ? 1 : 0);
};
